function largeDocumentText(kind, data = {}, language = "en") {
const part = Number(data.part || 1);
const total = Number(data.total || 1);
const chinese = language === "zh-CN";
const messages = chinese ? {
scope: `保存和普通导出只处理第 ${part}/${total} 段。要导出完整文档，请使用下方的全文导出按钮。`,
indexScope: "这是分段目录。请打开某一段进行编辑，或使用下方的全文导出按钮。",
loadHint: `大型文档：编辑器当前加载的是第 ${part}/${total} 段。“加载完整文件”只会完整加载当前这一段，不会合并全文。要导出完整文档，请使用分段卡片中的 Word、PDF、HTML 或 Markdown 按钮。`,
indexHint: `大型文档目录：请打开某一段进行编辑，或使用分段卡片中的 Word、PDF、HTML 或 Markdown 按钮，将全部 ${total} 段合并导出。`,
genericHint: `大型文档：保存和普通导出只处理编辑器当前内容。需要全部 ${total} 段时，请使用分段卡片中的全文导出按钮。`
} : {
scope: `Save and normal export use only part ${part} of ${total}. Use the full-document export buttons below for the whole file.`,
indexScope: "This is the segment index. Open a part to edit, or use the full-document export buttons below.",
loadHint: `Large document: the editor currently holds part ${part} of ${total}. "Load full file" loads this part completely, not the merged document. Use the segment card's Word/PDF/HTML/Markdown buttons to export the whole document.`,
indexHint: `Large document index: open a part to edit it, or use the segment card's Word/PDF/HTML/Markdown buttons to export all ${total} parts as one document.`,
genericHint: `Large document: save and normal export use the current editor content. Use the segment card's full-document export buttons when you need all ${total} parts.`
};
return messages[kind] || "";
}
